\midrule
\texttt{producers\_\_e4f664ea} & 0.836 & 0.018--0.097$^*$ & 0.819 & 2 \\
\texttt{detectives\_\_a46d5cd2} & 0.692 & 0.068 & 0.623 & 3 \\
